import{_ as e,o as a,c as i,ag as r}from"./chunks/framework.B_-t2C-M.js";const p=JSON.parse(`{"title":"What's Included","description":"","frontmatter":{},"headers":[],"relativePath":"guide/whats-included.md","filePath":"guide/whats-included.md"}`),n={name:"guide/whats-included.md"};function o(s,t,l,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="what-s-included" tabindex="-1">What&#39;s Included <a class="header-anchor" href="#what-s-included" aria-label="Permalink to &quot;What&#39;s Included&quot;">​</a></h1><p>Everything you need to build and launch a complete ecommerce backend — ready to use on day one.</p><h2 id="at-a-glance" tabindex="-1">At a Glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a Glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>API Endpoints</strong></td><td>325+ RESTful routes</td></tr><tr><td><strong>Database</strong></td><td>83 Eloquent models with 72 migrations</td></tr><tr><td><strong>Admin Panel</strong></td><td>Filament v3 with 46 management screens</td></tr><tr><td><strong>Automated Tests</strong></td><td>100% code coverage — all classes tested</td></tr><tr><td><strong>Payments</strong></td><td>Full Stripe integration (3DS, webhooks, refunds)</td></tr><tr><td><strong>Search</strong></td><td>Meilisearch with facets, filters, autocomplete</td></tr><tr><td><strong>Storage</strong></td><td>MinIO / AWS S3 ready</td></tr><tr><td><strong>Docker</strong></td><td>11 services, one-command setup</td></tr><tr><td><strong>Documentation</strong></td><td>This full docs site + 46 REST client test files</td></tr><tr><td><strong>Languages</strong></td><td>5 (EN, FR, AR, ES, DE)</td></tr><tr><td><strong>Currencies</strong></td><td>7 (USD, EUR, GBP, MAD, CAD, CHF, AED)</td></tr></tbody></table><hr><h2 id="core-modules" tabindex="-1">Core Modules <a class="header-anchor" href="#core-modules" aria-label="Permalink to &quot;Core Modules&quot;">​</a></h2><h3 id="authentication-security" tabindex="-1">Authentication &amp; Security <a class="header-anchor" href="#authentication-security" aria-label="Permalink to &quot;Authentication &amp; Security&quot;">​</a></h3><p>Register, login, token refresh, social OAuth (Google, Facebook, Apple), email verification, password reset, rate limiting (3 tiers), role-based access (customer, manager, admin with 57 granular permissions).</p><h3 id="product-catalog" tabindex="-1">Product Catalog <a class="header-anchor" href="#product-catalog" aria-label="Permalink to &quot;Product Catalog&quot;">​</a></h3><p>Products with unlimited variants, dynamic attributes, nested categories, brands, tags, collections, product translations, images via S3, flash sales, bundles, and volume-based price tiers.</p><h3 id="shopping-cart-checkout" tabindex="-1">Shopping Cart &amp; Checkout <a class="header-anchor" href="#shopping-cart-checkout" aria-label="Permalink to &quot;Shopping Cart &amp; Checkout&quot;">​</a></h3><p>Persistent cart, coupon validation and application (percentage, fixed, free shipping, buy-X-get-Y), smart shipping rate calculation, tax calculation via TaxService, address selection, stock deduction at checkout, and seamless order creation.</p><h3 id="orders-returns" tabindex="-1">Orders &amp; Returns <a class="header-anchor" href="#orders-returns" aria-label="Permalink to &quot;Orders &amp; Returns&quot;">​</a></h3><p>Full order lifecycle management, status history tracking, automatic invoice generation, cancellation workflow, and return request processing.</p><h3 id="stripe-payments" tabindex="-1">Stripe Payments <a class="header-anchor" href="#stripe-payments" aria-label="Permalink to &quot;Stripe Payments&quot;">​</a></h3><p>PaymentIntents with 3D Secure/SCA, saved payment methods, 6 webhook event handlers, refund processing with amount validation, internal wallet system with pessimistic locking, dispute tracking, and cash-on-delivery support.</p><h3 id="shipping-logistics" tabindex="-1">Shipping &amp; Logistics <a class="header-anchor" href="#shipping-logistics" aria-label="Permalink to &quot;Shipping &amp; Logistics&quot;">​</a></h3><p>Shipping zones with geographic targeting, multiple rate types (flat, weight, price, free), carrier tracking, estimated delivery dates, and return shipping.</p><h3 id="multi-warehouse-inventory" tabindex="-1">Multi-Warehouse Inventory <a class="header-anchor" href="#multi-warehouse-inventory" aria-label="Permalink to &quot;Multi-Warehouse Inventory&quot;">​</a></h3><p>Stock tracking per variant per warehouse, movement logs with before/after quantities, negative stock prevention, low stock alerts, automatic reorder notifications, and stock adjustment endpoints.</p><h3 id="marketing-suite" tabindex="-1">Marketing Suite <a class="header-anchor" href="#marketing-suite" aria-label="Permalink to &quot;Marketing Suite&quot;">​</a></h3><p>Coupons (percentage, fixed, BOGO, free shipping), promotions engine, flash sales with countdown, product bundles, banners, newsletters, and abandoned cart tracking.</p><h3 id="loyalty-retention" tabindex="-1">Loyalty &amp; Retention <a class="header-anchor" href="#loyalty-retention" aria-label="Permalink to &quot;Loyalty &amp; Retention&quot;">​</a></h3><p>Points system with earn/redeem, digital gift cards, affiliate program with conversion tracking, and customer group segmentation.</p><h3 id="content-management" tabindex="-1">Content Management <a class="header-anchor" href="#content-management" aria-label="Permalink to &quot;Content Management&quot;">​</a></h3><p>Blog with categories and drafts, static pages (FAQ, Terms, Privacy), contact form, and newsletter campaigns.</p><h3 id="search-discovery" tabindex="-1">Search &amp; Discovery <a class="header-anchor" href="#search-discovery" aria-label="Permalink to &quot;Search &amp; Discovery&quot;">​</a></h3><p>Meilisearch full-text search with typo tolerance, faceted filtering, price range filters, category navigation, autocomplete suggestions, and multiple sort options.</p><h3 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h3><p>15 email notification templates, in-app notifications, push notification support (Firebase FCM), custom webhook endpoints with delivery logs.</p><hr><h2 id="admin-panel" tabindex="-1">Admin Panel <a class="header-anchor" href="#admin-panel" aria-label="Permalink to &quot;Admin Panel&quot;">​</a></h2><p>46 fully-configured management screens powered by Filament v3:</p><ul><li><strong>Dashboard</strong> with live sales statistics</li><li><strong>Order management</strong> with Stripe refund integration</li><li><strong>Product management</strong> with variants, images, and translations</li><li><strong>Inventory management</strong> with stock adjustments</li><li><strong>Customer management</strong> with order history</li><li><strong>Coupon &amp; promotion management</strong></li><li><strong>Shipping configuration</strong> (zones, methods, rates)</li><li><strong>Blog &amp; content management</strong></li><li><strong>Full activity audit log</strong> for all admin actions</li><li>Bulk actions, advanced filtering, and export</li></ul><div class="tip custom-block"><p class="custom-block-title">See It in Action</p><p>Run the project locally to see the admin panel at <code>https://localhost/admin</code> with pre-loaded demo data.</p></div><hr><h2 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer Experience&quot;">​</a></h2><ul><li><strong>One-command Docker setup</strong> — 11 pre-configured services, just run <code>docker compose up -d</code></li><li><strong>50 seeders</strong> — Realistic demo data generated automatically</li><li><strong>46 REST client files</strong> — Test every endpoint from VS Code or JetBrains</li><li><strong>100% code coverage</strong> — Every controller, service, model, middleware, and policy tested</li><li><strong>Makefile shortcuts</strong> — <code>make fresh</code>, <code>make test</code>, <code>make urls</code>, and more</li><li><strong>Consistent API format</strong> — Every endpoint returns the same JSON structure</li><li><strong>Full documentation</strong> — This VitePress site is included in your purchase</li></ul><hr><h2 id="what-you-can-build-with-this" tabindex="-1">What You Can Build With This <a class="header-anchor" href="#what-you-can-build-with-this" aria-label="Permalink to &quot;What You Can Build With This&quot;">​</a></h2><ul><li>Mobile ecommerce app (iOS / Android)</li><li>Web storefront (React, Vue, Next.js, Nuxt)</li><li>Multi-vendor marketplace (extend with custom modules)</li><li>Subscription box service</li><li>Digital product store</li><li>B2B wholesale platform</li></ul>',41)])])}const g=e(n,[["render",o]]);export{p as __pageData,g as default};
